ALGORITHM ThompsonConstruction(RE)
INPUT: Regular Expression RE
OUTPUT: NFA = (Q, Σ, δ, q_start, q_accept)

BEGIN
 IF RE is a single symbol 'a' THEN
 // Create two states with transition on 'a'
 q_start := newState()
 q_accept := newState()
 δ(q_start, 'a') := {q_accept}
 RETURN NFA with states {q_start,q_accept}

 ELSE IF RE is ε (empty string) THEN
 // Create two states with ε-transition
 q_start := newState()
 q_accept := newState()
 ε_transition(q_start) := {q_accept}
 RETURN NFA

 ELSE IF RE is Union(R1, R2) THEN
 // Build NFAs for R1 and R2
 NFA1 := ThompsonConstruction(R1)
 NFA2 := ThompsonConstruction(R2)
 // Create new start and accept states
 q_start := newState()
 q_accept := newState()
 // Add ε-transitions from new start to both sub-NFAs
 ε_transition(q_start) := {NFA1.start, NFA2.start}
 // Add ε-transitions from both sub-NFAs to new accept
 ε_transition(NFA1.accept) := {q_accept}
 ε_transition(NFA2.accept) := {q_accept}
 RETURN combined NFA

 ELSE IF RE is Concatenation(R1, R2) THEN
 NFA1 := ThompsonConstruction(R1)
 NFA2 := ThompsonConstruction(R2)
 // Connect accept of R1 to start of R2
 ε_transition(NFA1.accept) := {NFA2.start}
 RETURN NFA with start=NFA1.start, accept=NFA2.accept

 ELSE IF RE is Star(R1) THEN
 // R1* means zero or more occurrences
 NFA1 := ThompsonConstruction(R1)
 q_start := newState()
 q_accept := newState()
 // ε from new start to sub-NFA start and new accept
 ε_transition(q_start) := {NFA1.start, q_accept}
 // ε from sub-NFA accept to sub-NFA start and new accept
 ε_transition(NFA1.accept) := {NFA1.start, q_accept}
 RETURN NFA
 END IF
END
